INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('hrbp助理 - 大连（实习）', '其他', '大连', '民营企业', 120, 130, '1. 熟练使用办公软件，具备一定的数据分析与文档整理能力；2. 具备基础的人力资源政策落地与项目支持能力', '1. 具备良好的沟通能力，能够与不同层级员工有效互动；2. 责任心强，工作细致，具备较强的执行力和学习能力；3. 具备团队协作意识，能快速适应工作环境并融入团队', 1, '极度友好', '1. 协助HRBP推动人力资源政策、制度及重点项目在业务部门的落地执行；2. 支持业务团队在人才管理、组织发展和员工关系方面的相关工作；3. 协助整理人力资源相关数据与材料，支持决策与汇报工作；4. 完成上级交办的其他人力资源支持性任务', 'OD 组织发展支持、员工关系支持、招聘数据分析', '本科及以上', '无强制专业限制', '27年毕业的本科或硕士，可实习3个月，每周到岗3天', '日常实习', '有人力资源相关实习经验；有数据分析相关经验', '120-130元/天', '46112', NULL, 'BOSS直聘平台获取', 'HRBP类', '甲方（企业自有 HR 岗）'), ('hrbp助理 - 茂名（社招）', '互联网 / IT', '茂名', '民营企业', 4000, 8000, '1. 掌握office系列办公软件使用技巧，具备基础的应用写作能力；2. 具备良好的数据分析能力；3. 具备基础的人力资源制度搭建与流程优化能力', '1. 逻辑思维敏捷，执行力强；2. 在人事工作中保持一定的敏锐度；3. 学习能力强，具备良好的业务理解能力', 1, '友好', '1. 理解公司业务逻辑，为健全公司人力资源制度献计献策；2. 梳理、优化公司业务部门流程制度；3. 学习、推进业务部门绩效管理工作；4. 分析、管控公司业务部门人力成本；5. 计划、配置业务部门人员组织架构；6. 完成上级领导安排的人事相关工作', '薪酬绩效支持、OD 组织发展支持、招聘数据分析', '本科及以上', '人力资源、管理学等相关专业优先', '经验不限，电商、互联网行业HRBP经验优先', '社招（应届生可投）', '有人力资源管理师相关证书；有电商/互联网行业HRBP经验', '4k-8k/月', '46112', NULL, 'BOSS直聘平台获取', 'HRBP类', '甲方（企业自有 HR 岗）'), ('HRBP - 岳阳（社招）', '企业服务/咨询', '岳阳', '民营企业', 8000, 10000, '1. 熟练操作常用Office办公软件；2. 具备组织诊断、人才体系搭建能力；3. 具备企业文化落地与团队激励体系搭建能力', '1. 工作认真负责，组织能力与责任心强，工作积极主动，有团队合作精神，做事细致严谨、条理性强；2. 具备领导力、亲和力、协同能力、冲突解决能力、洞察力、抗压能力，对人和组织有较高敏感度；3. 对公司忠诚，具有良好的保密意识', 0, '一般', '1. 文化建设：负责企业文化和价值理念的传播、落地与考核，公司各部门制度的执行与落实，打造适配业务的团队文化体系；2. 业务伙伴：支持和协助销售团队负责人制定计划、安排工作、解决日常运营问题，配合业务团队制定业务策略规划并跟踪落地，达成业务目标；3. 人才培养：负责人才引进把关、骨干队伍搭建、团队能力培养提升、员工晋升任免，搭建人员成长体系与成长方案，推动体系落地；4. 组织发展：优化完善团队组织架构，通过组织诊断做好人岗匹配，让合适的人在合适的岗位发挥价值；5. 关怀激励：关注员工工作与心理状态，及时疏导压力情绪，设计多元化激励措施，激发员工活力，营造积极向上的团队氛围', '招聘全流程执行、员工关系支持、OD 组织发展支持、薪酬绩效支持、招聘数据分析', '大专及以上', '无强制专业限制', '1-3年，有团队管理经验、HR全模块实践经验或业务管理经验优先', '社招（应届生可投）', '有人力资源管理师相关证书；有财税/法务服务行业HRBP经验', '8k-10k/月', '46112', NULL, 'BOSS直聘平台获取', 'HRBP类', '甲方（企业自有 HR 岗）'), ('HRBP助理 - 佛山（实习）', '互联网 / IT', '佛山', '民营企业', 130, 160, '1. 熟练使用办公软件；2. 具备基础的招聘流程执行与人事手续办理能力', '1. 性格活泼开朗、抗压能力强、执行力在线、热爱互联网行业；2. 具备良好的沟通表达能力与亲和力；3. 学习能力强，能快速适应工作节奏', 1, '极度友好', '1. 负责业务部门的简历筛选、电话邀约及面试安排；2. 办理员工入转调离手续等基础人事手续，完成领导安排的其他任务；3. 负责搭建员工关系，定期员工访谈，拉近同事间的距离', '招聘全流程执行、简历筛选与面试、员工关系支持', '本科及以上', '专业不限，人力资源等相关专业优先', '可实习3个月，每周到岗5天，接受在校生', '日常实习', '有社团管理经验或人事实习经验；有互联网行业HR实习经验', '130-160元/天', '46112', NULL, 'BOSS直聘平台获取', 'HRBP类', '甲方（企业自有 HR 岗）'), ('hrbp经理 - 贵阳（社招）', '制造', '贵阳', '民营企业', 12000, 20000, '1. 具备完整的人才筛选与评估体系，精通招聘、绩效、团队管理，熟悉人力法规；2. 熟练使用办公软件，具备基础的数据分析能力；3. 熟悉小团队管理模式，有团队搭建、人才梯队建设经验', '1. 沟通协调能力强，执行力好，抗压能力强，做事细致主动；2. 具备良好的业务理解能力，能搭建人力与业务的协同桥梁；3. 目标导向，具备较强的组织管理能力与结果意识', 0, '一般', '1. 深入农业机械业务一线，对接业务部门，搭建人力与业务协同桥梁，支撑团队扩张；2. 精通识人用人，拥有完整人才筛选体系，负责技术、销售、生产等岗位全流程招聘，快速补齐人才缺口，优化团队结构；3. 做好绩效全程跟踪，制定绩效目标、跟进执行落地，出具改善建议，提升团队效能；4. 统筹员工管理，化解关系矛盾，营造积极氛围，全力提升组织战斗力；5. 规范人事流程，落实人力制度，防范用工风险，定期人力复盘并给出组织优化建议；6. 开展文化建设与培训，增强团队凝聚力，助力公司拓展市场', '招聘全流程执行、渠道拓展与运营、薪酬绩效支持、员工关系支持、OD 组织发展支持、招聘数据分析', '大专及以上', '无强制专业限制', '1-3年HRBP工作经验，电商、制造行业经验优先', '社招（应届生可投）', '有人力资源管理师相关证书；有农业机械/制造/电商行业HRBP管理经验', '12k-20k/月', '46112', NULL, 'BOSS直聘平台获取', 'HRBP类', '甲方（企业自有 HR 岗）');